import styles from "./Dialogs.module.css";

const Dialogs = (props) => {
  return (
    <div>
      <div className="dialogs">
        <div className="dialog-items">
          <div className="dialog-item">Ilya</div>
          <div className="dialog-item">Alexey</div>
          <div className="dialog-item">Sergey</div>
          <div className="dialog-item">Artem</div>
          <div className="dialog-item">Dmitriy</div>
          <div className="dialog-item">Vladimir</div>
        </div>
        <div className="dialog-messages">
          <div className="message">Hi</div>
          <div className="message">How are you</div>
          <div className="message">Nice to meet you</div>
        </div>
      </div>
    </div>
  );
};

export default Dialogs;
